				}
			}

			if(inp.isEnabled()) {
				mc.thePlayer.sendQueue.addToSendQueue(new C0CPacketInput());
			}


			if(e.isPre()) {


				if(goofyC0C.isEnabled()) {
					if (mc.thePlayer.ticksExisted % 4 == 0) {
